import React from "react"
import ucsfLogo from './images/ucsfHealth.jpg'
import { properties } from '../../properties/properties.js'

const EXPENSES_ENDPOINT = `${properties.backend}expense/get_expense_table`
const COLUMNS_ENDPOINT = `${properties.backend}expense/get_columns/` // + expense_table_id
const SAVE_ENDPOINT = `${properties.backend}expense/save_report_config`

const desktopTopStyle = {
    width: "100%", backgroundColor: "#052049", color: "#ffffff", height: "40px", fontSize: "14px"
}

class ExpenseReportConfig extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            expenses: [],
            loadingExpenses: true,
            selectedExpense: "",
            columns: [],
            loadingColumns: false,
            selectedColumns: {},
            result: null,
            submitting: false
        };
    }

    componentDidMount() {
        this.fetchExpenses();
    }

    fetchExpenses() {
        let headers = new Headers();
        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(EXPENSES_ENDPOINT, {
            method: "GET",
            headers: headers
        })
        .then(response => response.json())
        .then(response => {
            this.setState({ expenses: response, loadingExpenses: false });
        })
        .catch(err => {
            console.log("Failed to load expenses:", err);
            this.setState({ expenses: [], loadingExpenses: false });
        });
    }

    fetchColumns(expenseTableId) {
        this.setState({ loadingColumns: true, columns: [], selectedColumns: {}, result: null });

        let headers = new Headers();
        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(COLUMNS_ENDPOINT + expenseTableId, {
            method: "GET",
            headers: headers
        })
        .then(response => response.json())
        .then(response => {
            this.setState({ columns: response, loadingColumns: false });
        })
        .catch(err => {
            console.log("Failed to load columns:", err);
            this.setState({ columns: [], loadingColumns: false });
        });
    }

    handleExpenseChange(expenseId) {
        this.setState({ selectedExpense: expenseId, selectedColumns: {}, result: null });
        if (expenseId) {
            this.fetchColumns(expenseId);
        } else {
            this.setState({ columns: [], loadingColumns: false });
        }
    }

    handleColumnToggle(columnId) {
        var selected = Object.assign({}, this.state.selectedColumns);
        if (selected[columnId]) {
            delete selected[columnId];
            // Re-sequence remaining orders
            var ordered = Object.keys(selected).sort(function(a, b) { return selected[a] - selected[b]; });
            var resequenced = {};
            for (var i = 0; i < ordered.length; i++) {
                resequenced[ordered[i]] = i + 1;
            }
            this.setState({ selectedColumns: resequenced });
        } else {
            var nextOrder = Object.keys(selected).length + 1;
            selected[columnId] = nextOrder;
            this.setState({ selectedColumns: selected });
        }
    }

    handleOrderChange(columnId, newOrder) {
        var parsed = parseInt(newOrder);
        if (isNaN(parsed) || parsed < 1) return;

        var selected = Object.assign({}, this.state.selectedColumns);
        var maxOrder = Object.keys(selected).length;
        if (parsed > maxOrder) parsed = maxOrder;

        var oldOrder = selected[columnId];
        if (oldOrder === parsed) return;

        // Shift other items
        var keys = Object.keys(selected);
        for (var i = 0; i < keys.length; i++) {
            var key = keys[i];
            if (key === String(columnId)) continue;
            var currentOrder = selected[key];
            if (oldOrder < parsed) {
                // Moving down: shift items between old+1..new up by 1
                if (currentOrder > oldOrder && currentOrder <= parsed) {
                    selected[key] = currentOrder - 1;
                }
            } else {
                // Moving up: shift items between new..old-1 down by 1
                if (currentOrder >= parsed && currentOrder < oldOrder) {
                    selected[key] = currentOrder + 1;
                }
            }
        }
        selected[columnId] = parsed;
        this.setState({ selectedColumns: selected });
    }

    moveColumn(columnId, direction) {
        var selected = Object.assign({}, this.state.selectedColumns);
        var currentOrder = selected[columnId];
        var maxOrder = Object.keys(selected).length;
        var newOrder = currentOrder + direction;
        if (newOrder < 1 || newOrder > maxOrder) return;
        this.handleOrderChange(columnId, newOrder);
    }

    handleSelectAll() {
        var selected = {};
        for (var i = 0; i < this.state.columns.length; i++) {
            selected[this.state.columns[i].id] = i + 1;
        }
        this.setState({ selectedColumns: selected });
    }

    handleDeselectAll() {
        this.setState({ selectedColumns: {} });
    }

    handleSubmit() {
        var selectedCount = Object.keys(this.state.selectedColumns).length;
        if (!this.state.selectedExpense) {
            this.setState({ result: { type: "error", message: "Please select an expense type." } });
            return;
        }
        if (selectedCount === 0) {
            this.setState({ result: { type: "error", message: "Please select at least one column." } });
            return;
        }

        this.setState({ submitting: true, result: null });

        // Build payload: array of { column_id, column_name, order }
        var selected = this.state.selectedColumns;
        var columns = this.state.columns;
        var configColumns = [];

        var columnMap = {};
        for (var i = 0; i < columns.length; i++) {
            columnMap[columns[i].id] = columns[i];
        }

        var keys = Object.keys(selected);
        for (var i = 0; i < keys.length; i++) {
            var colId = keys[i];
            var col = columnMap[colId];
            if (col) {
                configColumns.push({
                    column_id: parseInt(colId),
                    column_name: col.column_name,
                    column_number: col.column_number,
                    display_order: selected[colId]
                });
            }
        }

        configColumns.sort(function(a, b) { return a.display_order - b.display_order; });

        var payload = {
            expense_table_id: parseInt(this.state.selectedExpense),
            columns: configColumns
        };

        fetch(SAVE_ENDPOINT, {
            method: "POST",
            headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
            body: JSON.stringify(payload)
        })
        .then(response => {
            return response.json().then(data => {
                if (!response.ok) {
                    throw new Error(data.error || data.message || "Save failed");
                }
                return data;
            });
        })
        .then(data => {
            this.setState({ submitting: false, result: { type: "success", message: data.message || "Configuration saved successfully!" } });
        })
        .catch(err => {
            this.setState({ submitting: false, result: { type: "error", message: err.message || "Something went wrong." } });
        });
    }

    getSelectedColumnsSorted() {
        var selected = this.state.selectedColumns;
        var columns = this.state.columns;
        var result = [];

        var columnMap = {};
        for (var i = 0; i < columns.length; i++) {
            columnMap[columns[i].id] = columns[i];
        }

        var keys = Object.keys(selected);
        for (var i = 0; i < keys.length; i++) {
            var col = columnMap[keys[i]];
            if (col) {
                result.push({ id: keys[i], column_name: col.column_name, data_type: col.data_type, order: selected[keys[i]] });
            }
        }
        result.sort(function(a, b) { return a.order - b.order; });
        return result;
    }

    renderExpenseSelection() {
        return (
            <div style={{ padding: "20px", background: "#ffffff", border: "1px solid #e2e6ed", borderRadius: "6px" }}>
                <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "14px" }}>
                    <span style={{ width: "26px", height: "26px", borderRadius: "50%", background: "#052049", color: "#fff", fontSize: "13px", fontWeight: "700", display: "flex", alignItems: "center", justifyContent: "center" }}>1</span>
                    <span style={{ fontSize: "16px", fontWeight: "600" }}>Select Expense Type</span>
                </div>
                <select
                    style={{ width: "100%", padding: "11px 14px", fontSize: "14px", border: "1px solid #e2e6ed", borderRadius: "6px", background: "#ffffff", color: "#2c3345" }}
                    value={this.state.selectedExpense}
                    onChange={(e) => this.handleExpenseChange(e.target.value)}
                    disabled={this.state.loadingExpenses}
                >
                    <option value="">{this.state.loadingExpenses ? "Loading expenses..." : "\u2014 Select an expense type \u2014"}</option>
                    {this.state.expenses.map((exp) => (
                        <option key={exp.id} value={exp.id}>{exp.name}</option>
                    ))}
                </select>
            </div>
        );
    }

    renderColumnSelection() {
        if (!this.state.selectedExpense) return null;

        if (this.state.loadingColumns) {
            return (
                <div style={{ marginTop: "20px", padding: "20px", background: "#ffffff", border: "1px solid #e2e6ed", borderRadius: "6px", textAlign: "center", color: "#7c8ba1", fontSize: "14px" }}>
                    Loading columns...
                </div>
            );
        }

        if (this.state.columns.length === 0) {
            return (
                <div style={{ marginTop: "20px", padding: "20px", background: "#ffffff", border: "1px solid #e2e6ed", borderRadius: "6px", textAlign: "center", color: "#7c8ba1", fontSize: "14px" }}>
                    No columns found for this expense type.
                </div>
            );
        }

        var selectedCount = Object.keys(this.state.selectedColumns).length;
        var totalCount = this.state.columns.length;

        return (
            <div style={{ marginTop: "20px", padding: "20px", background: "#ffffff", border: "1px solid #e2e6ed", borderRadius: "6px" }}>
                <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "6px" }}>
                    <span style={{ width: "26px", height: "26px", borderRadius: "50%", background: "#052049", color: "#fff", fontSize: "13px", fontWeight: "700", display: "flex", alignItems: "center", justifyContent: "center" }}>2</span>
                    <span style={{ fontSize: "16px", fontWeight: "600" }}>Select Columns</span>
                </div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "14px" }}>
                    <p style={{ fontSize: "13px", color: "#7c8ba1", margin: 0 }}>Choose which columns to include and click to select. ({selectedCount} of {totalCount} selected)</p>
                    <div style={{ display: "flex", gap: "8px" }}>
                        <span style={{ fontSize: "13px", color: "#052049", fontWeight: "600", cursor: "pointer", textDecoration: "underline" }} onClick={() => this.handleSelectAll()}>Select All</span>
                        {selectedCount > 0 && (
                            <span style={{ fontSize: "13px", color: "#d64545", fontWeight: "600", cursor: "pointer", textDecoration: "underline" }} onClick={() => this.handleDeselectAll()}>Clear</span>
                        )}
                    </div>
                </div>

                <div style={{ display: "flex", flexWrap: "wrap", gap: "8px" }}>
                    {this.state.columns.map((col) => {
                        var isSelected = this.state.selectedColumns[col.id] !== undefined;
                        var order = this.state.selectedColumns[col.id];
                        return (
                            <div key={col.id}
                                style={{
                                    display: "flex",
                                    alignItems: "center",
                                    gap: "8px",
                                    padding: "8px 14px",
                                    borderRadius: "6px",
                                    border: isSelected ? "2px solid #052049" : "1px solid #e2e6ed",
                                    background: isSelected ? "#e8f0fe" : "#fafbfc",
                                    cursor: "pointer",
                                    transition: "all 0.15s",
                                    userSelect: "none"
                                }}
                                onClick={() => this.handleColumnToggle(col.id)}
                            >
                                <div style={{
                                    width: "18px", height: "18px", borderRadius: "4px", flexShrink: 0,
                                    border: isSelected ? "2px solid #052049" : "2px solid #ccc",
                                    background: isSelected ? "#052049" : "#ffffff",
                                    display: "flex", alignItems: "center", justifyContent: "center"
                                }}>
                                    {isSelected && <span style={{ color: "#ffffff", fontSize: "12px", fontWeight: "bold" }}>&#10003;</span>}
                                </div>
                                <span style={{ fontSize: "13px", fontWeight: isSelected ? "600" : "400", color: isSelected ? "#052049" : "#2c3345" }}>
                                    {col.column_name}
                                </span>
                                <span style={{ fontSize: "11px", color: "#7c8ba1", background: "#f0f2f5", padding: "2px 6px", borderRadius: "4px" }}>
                                    {col.data_type}
                                </span>
                                {isSelected && (
                                    <span style={{ fontSize: "11px", fontWeight: "700", color: "#ffffff", background: "#052049", borderRadius: "50%", width: "20px", height: "20px", display: "flex", alignItems: "center", justifyContent: "center", marginLeft: "2px" }}>
                                        {order}
                                    </span>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
        );
    }

    renderOrderConfig() {
        var sortedSelected = this.getSelectedColumnsSorted();
        if (sortedSelected.length === 0) return null;

        return (
            <div style={{ marginTop: "20px", padding: "20px", background: "#ffffff", border: "1px solid #e2e6ed", borderRadius: "6px" }}>
                <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "6px" }}>
                    <span style={{ width: "26px", height: "26px", borderRadius: "50%", background: "#052049", color: "#fff", fontSize: "13px", fontWeight: "700", display: "flex", alignItems: "center", justifyContent: "center" }}>3</span>
                    <span style={{ fontSize: "16px", fontWeight: "600" }}>Arrange Column Order</span>
                </div>
                <p style={{ fontSize: "13px", color: "#7c8ba1", marginBottom: "14px" }}>Use the arrows to reorder columns. The order determines how columns appear in the report.</p>

                <div style={{ border: "1px solid #e2e6ed", borderRadius: "6px", overflow: "hidden" }}>
                    {sortedSelected.map((col, idx) => (
                        <div key={col.id}
                            style={{
                                display: "flex",
                                alignItems: "center",
                                gap: "12px",
                                padding: "10px 16px",
                                borderBottom: idx < sortedSelected.length - 1 ? "1px solid #e2e6ed" : "none",
                                background: idx % 2 === 0 ? "#fafbfc" : "#ffffff"
                            }}
                        >
                            {/* Order number */}
                            <span style={{ fontSize: "14px", fontWeight: "700", color: "#052049", width: "24px", textAlign: "center" }}>
                                {col.order}
                            </span>

                            {/* Arrows */}
                            <div style={{ display: "flex", flexDirection: "column", gap: "2px" }}>
                                <span
                                    style={{ cursor: col.order > 1 ? "pointer" : "not-allowed", fontSize: "12px", color: col.order > 1 ? "#052049" : "#ccc", lineHeight: "1", userSelect: "none" }}
                                    onClick={() => this.moveColumn(col.id, -1)}
                                >&#9650;</span>
                                <span
                                    style={{ cursor: col.order < sortedSelected.length ? "pointer" : "not-allowed", fontSize: "12px", color: col.order < sortedSelected.length ? "#052049" : "#ccc", lineHeight: "1", userSelect: "none" }}
                                    onClick={() => this.moveColumn(col.id, 1)}
                                >&#9660;</span>
                            </div>

                            {/* Column name */}
                            <span style={{ fontSize: "14px", fontWeight: "500", color: "#2c3345", flex: 1 }}>
                                {col.column_name}
                            </span>

                            {/* Data type badge */}
                            <span style={{ fontSize: "11px", color: "#7c8ba1", background: "#f0f2f5", padding: "2px 8px", borderRadius: "4px" }}>
                                {col.data_type}
                            </span>

                            {/* Remove */}
                            <span
                                style={{ fontSize: "13px", color: "#d64545", cursor: "pointer", fontWeight: "600" }}
                                onClick={() => this.handleColumnToggle(col.id)}
                            >&#10005;</span>
                        </div>
                    ))}
                </div>
            </div>
        );
    }

    renderResult() {
        if (!this.state.result) return null;
        var isSuccess = this.state.result.type === "success";
        return (
            <div style={{ display: "flex", alignItems: "center", gap: "10px", padding: "14px 18px", borderRadius: "6px", fontSize: "14px", fontWeight: "500", marginTop: "20px", background: isSuccess ? "#eaf7f0" : "#fdf0f0", color: isSuccess ? "#2a6e4a" : "#d64545", border: isSuccess ? "1px solid #c2e3d3" : "1px solid #f0c2c2" }}>
                <span style={{ fontSize: "18px" }}>{isSuccess ? "\u2713" : "\u2717"}</span>
                <span>{this.state.result.message}</span>
            </div>
        );
    }

    render() {
        var content = [];
        var selectedCount = Object.keys(this.state.selectedColumns).length;

        // UCSF Header
        content.push(
            <div key="topbar" style={desktopTopStyle}>
                <span style={{ left: "30px", top: "10px", position: "relative" }}>University of California San Francisco</span>
            </div>
        );
        content.push(
            <div key="header" style={{ width: "100%", height: "100px", boxShadow: "0px 0px 8px 2px #CCCCCC" }}>
                <div style={{ marginLeft: "4%" }}>
                    <div style={{ float: "left", display: "grid", height: "100px" }}>
                        <img src={ucsfLogo} style={{ height: "30px", margin: "auto" }} alt="UCSF Logo" />
                    </div>
                    <div style={{ float: "left", marginLeft: "30px", fontFamily: "Arial", fontSize: "18px", height: "100px", display: "grid" }}>
                        <span style={{ margin: "auto" }}>- Expense Report Configuration</span>
                    </div>
                </div>
            </div>
        );

        // Main content
        content.push(
            <div key="main" style={{ maxWidth: "760px", margin: "40px auto", padding: "0 20px" }}>

                {/* Step 1 - Expense Selection */}
                {this.renderExpenseSelection()}

                {/* Step 2 - Column Selection */}
                {this.renderColumnSelection()}

                {/* Step 3 - Order Configuration */}
                {this.renderOrderConfig()}

                {/* Result Banner */}
                {this.renderResult()}

                {/* Submit Button */}
                {selectedCount > 0 && (
                    <button
                        style={{ width: "100%", padding: "14px", fontSize: "15px", fontWeight: "700", background: "#052049", color: "#ffffff", border: "none", borderRadius: "6px", cursor: this.state.submitting ? "not-allowed" : "pointer", marginTop: "20px", opacity: this.state.submitting ? 0.6 : 1 }}
                        onClick={() => this.handleSubmit()}
                        disabled={this.state.submitting}
                    >
                        {this.state.submitting ? "Saving..." : "Save Configuration"}
                    </button>
                )}
            </div>
        );

        return (
            <div style={{ minHeight: "500px", marginLeft: "0px", marginRight: "0px" }}>
                {content}
            </div>
        );
    }
}

export default ExpenseReportConfig
